function Get-SavedCookies {
    if (-not (Test-Path $Config.CookieFile)) {
        Write-Log "No saved cookies found." "WARN"
        return $null
    }
    try {
        $json   = Get-Content $Config.CookieFile -Raw | ConvertFrom-Json
        $ageHrs = [math]::Round(((Get-Date) - (Get-Date $json.SavedAt)).TotalHours, 1)
        Write-Log "Saved cookies found - age: $ageHrs hours"
        return $json
    } catch {
        Write-Log "Cookie file unreadable: $($_.Exception.Message)" "WARN"
        return $null
    }
}

