function Validate-CSV {
    param([string]$FilePath)
    try {
        $data = Import-Csv -Path $FilePath
        $rows = $data.Count
        $cols = $data[0].PSObject.Properties.Name
        Write-Log "CSV: $rows rows | Columns: $($cols -join ', ')" "SUCCESS"
        return @{ Valid = ($rows -ge $Config.MinExpectedRows); Rows = $rows; Columns = $cols }
    } catch {
        Write-Log "CSV validation error: $($_.Exception.Message)" "ERROR"
        return @{ Valid = $false; Rows = 0; Columns = @() }
    }
}

